// Get webhook body
const webhookItem = $('Webhook Remessa').first().json;
const body = webhookItem.body ?? webhookItem;
const contas = body.contas ?? [];

// Get Omie credentials from sys_config rows
const configRows = $('Get Omie Credentials').all().map(i => i.json);
const cfg = {};
for (const row of configRows) {
  cfg[row.chave] = row.valor;
}

// Determine sandbox vs production
const isSandbox = cfg.omie_sandbox_mode === 'true';
const appKey = (isSandbox && cfg.omie_sandbox_app_key) ? cfg.omie_sandbox_app_key : cfg.omie_app_key;
const appSecret = (isSandbox && cfg.omie_sandbox_app_secret) ? cfg.omie_sandbox_app_secret : cfg.omie_app_secret;

if (!appKey || !appSecret) {
  throw new Error('Credenciais Omie nao configuradas em sys_config');
}

const OMIE_URL = 'https://app.omie.com.br/api/v1/financas/contapagar/';
const SB_URL = $vars.supabase_url;
const SB_KEY = $vars.supabase_service_role_key;
const SB_HEADERS = {
  'apikey': SB_KEY,
  'Authorization': `Bearer ${SB_KEY}`,
  'Content-Type': 'application/json'
};

function toOmieDate(d) {
  if (!d) return new Date().toLocaleDateString('pt-BR', {day:'2-digit',month:'2-digit',year:'numeric'});
  const [y, m, dd] = d.split('-');
  return `${dd}/${m}/${y}`;
}

const resultados = [];
let incluidos = 0;
let erros = 0;

for (const cp of contas) {
  if (!cp.id) continue;
  if (cp.omie_cp_id) {
    resultados.push({ cpId: cp.id, omieId: cp.omie_cp_id, status: 'ja_existe' });
    incluidos++;
    continue;
  }
  try {
    const omieBody = {
      call: 'IncluirContaPagar',
      app_key: appKey,
      app_secret: appSecret,
      param: [{
        cabecalho: {
          nCodFornecedor: cp.omie_fornecedor_id ?? 0,
          cNumDocumento: cp.numero_documento ?? `TEG-${cp.id.slice(0,8).toUpperCase()}`,
          dDtEmissao: toOmieDate(cp.data_emissao),
          dDtVenc: toOmieDate(cp.data_vencimento),
          nValorDocumento: Number(cp.valor_original),
          cObservacao: cp.descricao ?? `CP TEG+ ${cp.id}`
        }
      }]
    };
    const omieRes = await fetch(OMIE_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(omieBody)
    });
    const omieData = await omieRes.json();
    if (omieData.faultstring) throw new Error(omieData.faultstring);
    const nCodCP = omieData.nCodCP;
    await fetch(`${SB_URL}/rest/v1/fin_contas_pagar?id=eq.${cp.id}`, {
      method: 'PATCH',
      headers: { ...SB_HEADERS, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        omie_cp_id: nCodCP,
        remessa_status: 'enviada',
        remessa_enviada_em: new Date().toISOString(),
        remessa_id: String(nCodCP)
      })
    });
    resultados.push({ cpId: cp.id, omieId: nCodCP, status: 'incluido' });
    incluidos++;
  } catch (err) {
    const msg = String(err.message ?? 'Erro desconhecido');
    await fetch(`${SB_URL}/rest/v1/fin_contas_pagar?id=eq.${cp.id}`, {
      method: 'PATCH',
      headers: SB_HEADERS,
      body: JSON.stringify({ remessa_status: 'erro', remessa_erro: msg })
    });
    resultados.push({ cpId: cp.id, omieId: null, status: 'erro', mensagem: msg });
    erros++;
  }
}

const remessaId = `REM-OMIE-${Date.now()}`;
await fetch(`${SB_URL}/rest/v1/fin_sync_log`, {
  method: 'POST',
  headers: SB_HEADERS,
  body: JSON.stringify({
    dominio: 'remessa_pagamento',
    status: erros === 0 ? 'success' : 'partial',
    registros: contas.length,
    mensagem: `Remessa Omie: ${incluidos} incluida(s), ${erros} erro(s). Ambiente: ${isSandbox ? 'teste' : 'producao'}`,
    executado_por: 'n8n'
  })
});

return [{ json: { success: true, remessaId, registros: contas.length, incluidos, erros, resultados, ambiente: isSandbox ? 'teste' : 'producao' } }];
